	private Optional<JoinOrderPlan> orderedCostPlan(List<TupleExpr> orderedArgs, Set<String> initiallyBoundVars,
			Algorithm algorithm, List<FilterConstraint> deferredFilters) {
		if (orderedArgs == null || orderedArgs.isEmpty()) {
			return Optional.empty();
		}
		List<TupleExpr> expressions = List.copyOf(orderedArgs);
		Set<String> initialBindings = initiallyBoundVars == null || initiallyBoundVars.isEmpty()
				? Set.of()
				: Set.copyOf(initiallyBoundVars);
		Set<String> boundVars = new LinkedHashSet<>(initialBindings);
		List<TupleExpr> prefixFactors = new ArrayList<>(expressions.size());
		List<PlanStep> steps = new ArrayList<>(expressions.size());
		boolean[] appliedFilters = deferredFilters.isEmpty() ? null : new boolean[deferredFilters.size()];
		double prefixRows = 1.0d;
		double totalWorkRows = 0.0d;

		for (int factorIndex = 0; factorIndex < expressions.size(); factorIndex++) {
			TupleExpr factor = expressions.get(factorIndex);
			Set<String> boundVarsBefore = boundVars.isEmpty() ? Set.of() : Set.copyOf(boundVars);
			LmdbCascadesConnectedJoinPlanner.Step estimate = LmdbCascadesConnectedJoinPlanner.estimateStep(
					expressions, factorIndex, boundVarsBefore, prefixRows, true, prefixFactors, this, this,
					EstimationTier.STANDARD);
			if (estimate == null) {
				return Optional.empty();
			}
			double factorOutputRows = finiteNonNegative(estimate.outputRows(), prefixRows);
			double prefixOutputRows = factorOutputRows;
			double stepWorkRows = finiteNonNegative(estimate.workRows(), factorOutputRows);
			Map<String, String> stringMetrics = new LinkedHashMap<>(estimate.stringMetrics());
			Map<String, Double> doubleMetrics = new LinkedHashMap<>(estimate.doubleMetrics());
			List<Integer> appliedFilterIndexes = new ArrayList<>();

			boundVars.addAll(LmdbJoinPlanSupport.plannerBindingNames(factor.getBindingNames()));
			if (appliedFilters != null) {
				List<TupleExpr> filterPrefix = new ArrayList<>(prefixFactors.size() + 1);
				filterPrefix.addAll(prefixFactors);
				filterPrefix.add(factor);
				for (int filterIndex = 0; filterIndex < deferredFilters.size(); filterIndex++) {
					FilterConstraint filter = deferredFilters.get(filterIndex);
					if (appliedFilters[filterIndex] || filter == null
							|| !boundVars.containsAll(filter.getRequiredVars())) {
						continue;
					}
					double filterInputRows = prefixOutputRows;
					CostContext filterContext = CostContext.forOptimization(Set.copyOf(boundVars), filterInputRows,
							Double.NaN, true, true, Map.of(), filterPrefix);
					FilterCostEstimate filterCost = estimateFilterCost(filter, filterContext)
							.orElseGet(() -> fallbackFilterCost(filter, filterInputRows));
					prefixOutputRows = finiteNonNegative(filterCost.outputRows(), prefixOutputRows);
					stepWorkRows += finiteNonNegative(filterCost.workRows(), 0.0d);
					stringMetrics.putAll(filterCost.stringMetrics());
					doubleMetrics.putAll(filterCost.doubleMetrics());
					appliedFilterIndexes.add(filterIndex);
					appliedFilters[filterIndex] = true;
				}
			}

			doubleMetrics.put(TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, factorOutputRows);
			doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_FINAL_ROWS, prefixOutputRows);
			doubleMetrics.put(TelemetryMetricNames.PLANNED_WORK_ROWS, stepWorkRows);
			doubleMetrics.put(TelemetryMetricNames.PLANNED_COST_WORK_ROWS, stepWorkRows);
			steps.add(new PlanStep(boundVarsBefore, factorOutputRows, prefixOutputRows, stepWorkRows,
					Map.copyOf(stringMetrics), Map.copyOf(doubleMetrics), List.copyOf(appliedFilterIndexes)));
			totalWorkRows = saturatingAdd(totalWorkRows, stepWorkRows);
			prefixRows = prefixOutputRows;
			prefixFactors.add(factor);
		}

		Map<String, String> summaryStrings = Map.of(
				TelemetryMetricNames.PLANNER_ID, "lmdb-ordered-cost",
				TelemetryMetricNames.OPTIMIZER_PHYSICAL_REFINEMENT,
				"costModel=lmdb, joinOrder="
						+ (algorithm == Algorithm.DYNAMIC_PROGRAMMING ? "dynamic-programming" : "greedy"),
				TelemetryMetricNames.PLANNED_ESTIMATE_SOURCE, "lmdb-ordered-cost");
		Map<String, Double> summaryDoubles = Map.of(
				TelemetryMetricNames.PLANNED_CARDINALITY_ROWS, prefixRows,
				TelemetryMetricNames.PLANNED_COST_FINAL_ROWS, prefixRows,
				TelemetryMetricNames.PLANNED_WORK_ROWS, totalWorkRows,
				TelemetryMetricNames.PLANNED_COST_WORK_ROWS, totalWorkRows);
		List<String> diagnostics = List.of("input: algorithm=" + algorithm + " initiallyBoundVars="
				+ initialBindings + " plannedBoundVars=" + boundVars);
		return Optional.of(new JoinOrderPlan(expressions, prefixRows, totalWorkRows, diagnostics, summaryStrings,
				summaryDoubles, steps));
	}

	private static FilterCostEstimate fallbackFilterCost(FilterConstraint filter, double inputRows) {
		double ratio = filter.getEstimatedPassRatio();
		if (!Double.isFinite(ratio) || ratio < 0.0d || ratio > 1.0d) {
			ratio = 1.0d;
		}
		double outputRows = inputRows * ratio;
		double workRows = filter.getConditionCost() == FILTER_COST_EXPENSIVE ? inputRows : 0.0d;
		return new FilterCostEstimate(workRows, outputRows, ratio);
	}

